import{_ as o,o as t,c as l,ai as a}from"./chunks/framework.CsYGeNYI.js";const v=JSON.parse('{"title":"Elevated Mode","description":"","frontmatter":{"summary":"Elevated exec mode and /elevated directives","read_when":["Adjusting elevated mode defaults, allowlists, or slash command behavior"],"title":"Elevated Mode"},"headers":[],"relativePath":"tools/elevated.md","filePath":"tools/elevated.md","lastUpdated":null}'),s={name:"tools/elevated.md"};function d(i,e,n,r,c,h){return t(),l("div",null,[...e[0]||(e[0]=[a('<h1 id="elevated-mode-elevated-directives" tabindex="-1"><a class="header-anchor" href="#elevated-mode-elevated-directives">#</a> Elevated Mode (/elevated directives)</h1><h2 id="what-it-does" tabindex="-1"><a class="header-anchor" href="#what-it-does">#</a> What it does</h2><ul><li><code>/elevated on</code> runs on the gateway host and keeps exec approvals (same as <code>/elevated ask</code>).</li><li><code>/elevated full</code> runs on the gateway host <strong>and</strong> auto-approves exec (skips exec approvals).</li><li><code>/elevated ask</code> runs on the gateway host but keeps exec approvals (same as <code>/elevated on</code>).</li><li><code>on</code>/<code>ask</code> do <strong>not</strong> force <code>exec.security=full</code>; configured security/ask policy still applies.</li><li>Only changes behavior when the agent is <strong>sandboxed</strong> (otherwise exec already runs on the host).</li><li>Directive forms: <code>/elevated on|off|ask|full</code>, <code>/elev on|off|ask|full</code>.</li><li>Only <code>on|off|ask|full</code> are accepted; anything else returns a hint and does not change state.</li></ul><h2 id="what-it-controls-and-what-it-doesn-t" tabindex="-1"><a class="header-anchor" href="#what-it-controls-and-what-it-doesn-t">#</a> What it controls (and what it doesn’t)</h2><ul><li><strong>Availability gates</strong>: <code>tools.elevated</code> is the global baseline. <code>agents.list[].tools.elevated</code> can further restrict elevated per agent (both must allow).</li><li><strong>Per-session state</strong>: <code>/elevated on|off|ask|full</code> sets the elevated level for the current session key.</li><li><strong>Inline directive</strong>: <code>/elevated on|ask|full</code> inside a message applies to that message only.</li><li><strong>Groups</strong>: In group chats, elevated directives are only honored when the agent is mentioned. Command-only messages that bypass mention requirements are treated as mentioned.</li><li><strong>Host execution</strong>: elevated forces <code>exec</code> onto the gateway host; <code>full</code> also sets <code>security=full</code>.</li><li><strong>Approvals</strong>: <code>full</code> skips exec approvals; <code>on</code>/<code>ask</code> honor them when allowlist/ask rules require.</li><li><strong>Unsandboxed agents</strong>: no-op for location; only affects gating, logging, and status.</li><li><strong>Tool policy still applies</strong>: if <code>exec</code> is denied by tool policy, elevated cannot be used.</li><li><strong>Separate from <code>/exec</code></strong>: <code>/exec</code> adjusts per-session defaults for authorized senders and does not require elevated.</li></ul><h2 id="resolution-order" tabindex="-1"><a class="header-anchor" href="#resolution-order">#</a> Resolution order</h2><ol><li>Inline directive on the message (applies only to that message).</li><li>Session override (set by sending a directive-only message).</li><li>Global default (<code>agents.defaults.elevatedDefault</code> in config).</li></ol><h2 id="setting-a-session-default" tabindex="-1"><a class="header-anchor" href="#setting-a-session-default">#</a> Setting a session default</h2><ul><li>Send a message that is <strong>only</strong> the directive (whitespace allowed), e.g. <code>/elevated full</code>.</li><li>Confirmation reply is sent (<code>Elevated mode set to full...</code> / <code>Elevated mode disabled.</code>).</li><li>If elevated access is disabled or the sender is not on the approved allowlist, the directive replies with an actionable error and does not change session state.</li><li>Send <code>/elevated</code> (or <code>/elevated:</code>) with no argument to see the current elevated level.</li></ul><h2 id="availability-allowlists" tabindex="-1"><a class="header-anchor" href="#availability-allowlists">#</a> Availability + allowlists</h2><ul><li>Feature gate: <code>tools.elevated.enabled</code> (default can be off via config even if the code supports it).</li><li>Sender allowlist: <code>tools.elevated.allowFrom</code> with per-provider allowlists (e.g. <code>discord</code>, <code>whatsapp</code>).</li><li>Per-agent gate: <code>agents.list[].tools.elevated.enabled</code> (optional; can only further restrict).</li><li>Per-agent allowlist: <code>agents.list[].tools.elevated.allowFrom</code> (optional; when set, the sender must match <strong>both</strong> global + per-agent allowlists).</li><li>Discord fallback: if <code>tools.elevated.allowFrom.discord</code> is omitted, the <code>channels.discord.dm.allowFrom</code> list is used as a fallback. Set <code>tools.elevated.allowFrom.discord</code> (even <code>[]</code>) to override. Per-agent allowlists do <strong>not</strong> use the fallback.</li><li>All gates must pass; otherwise elevated is treated as unavailable.</li></ul><h2 id="logging-status" tabindex="-1"><a class="header-anchor" href="#logging-status">#</a> Logging + status</h2><ul><li>Elevated exec calls are logged at info level.</li><li>Session status includes elevated mode (e.g. <code>elevated=ask</code>, <code>elevated=full</code>).</li></ul>',13)])])}const u=o(s,[["render",d]]);export{v as __pageData,u as default};
